/**
 * @fileoverview GridTable Feature — Side panel mixin.
 *
 * Lazy-loaded when `showSidePanel: true` is set in config.
 * Adds a collapsible side panel with column visibility controls,
 * search, and custom panel sections.
 *
 * @module module/GridTable/features/panel
 */

import razyui from '../../../index.js';

import {
    buildSidePanel,
    activatePanel,
    buildColumnList,
    rebuildPanelColumnList,
} from '../view.js';

import {
    startPanelColumnDrag,
    handlePanelColumnDrag,
    finishPanelColumnDrag,
} from '../events.js';

/**
 * Install the side panel feature onto a GridTable ctx bridge.
 *
 * @param {object} ctx — the shared context bridge
 */
export function installPanel(ctx) {
    ctx._panelInstalled = true;

    // Build panel DOM
    buildSidePanel(ctx);

    // Wire ctx methods
    ctx.activatePanel         = (name) => activatePanel(ctx, name);
    ctx.rebuildPanelColumnList = ()     => rebuildPanelColumnList(ctx);
    ctx.startPanelColumnDrag  = (n, e) => startPanelColumnDrag(ctx, n, e);
    ctx.handlePanelColumnDrag = (e)    => handlePanelColumnDrag(ctx, e);
    ctx.finishPanelColumnDrag = ()     => finishPanelColumnDrag(ctx);

    /**
     * Open a named panel section.
     * @param {string} name
     */
    ctx.openPanel = (name) => {
        if (!ctx.sidePanel) return;
        const isCollapsed = ctx.sidePanel.hasClass('is-collapsed');
        // If already open on the same section, toggle it closed
        if (!isCollapsed) {
            const activeBtn = ctx.panelBar?.find('.grid-table-bar-btn.is-active')[0];
            if (activeBtn && activeBtn.getAttribute('name') === name) {
                ctx.closePanel();
                return;
            }
        }
        ctx.sidePanel.removeClass('is-collapsed');
        ctx.container.addClass('is-panel-transitioning');
        ctx.container[0].style.setProperty('--panel-inset', '260px');
        activatePanel(ctx, name);
        if (name === 'columns') {
            rebuildPanelColumnList(ctx);
        }
        setTimeout(() => { ctx.reflowColumns(); ctx.container.removeClass('is-panel-transitioning'); }, 220);
    };

    /**
     * Close the side panel.
     */
    ctx.closePanel = () => {
        if (!ctx.sidePanel) return;
        ctx.sidePanel.addClass('is-collapsed');
        ctx.container.addClass('is-panel-transitioning');
        ctx.container[0].style.setProperty('--panel-inset', '0px');
        setTimeout(() => { ctx.reflowColumns(); ctx.container.removeClass('is-panel-transitioning'); }, 220);
        // Remove active highlight from bar buttons
        if (ctx.panelBar) {
            ctx.panelBar.find('.grid-table-bar-btn.is-active').each(b => {
                razyui(b).removeClass('is-active');
            });
        }
    };

    /**
     * Register a custom panel section.
     * @param {string} name
     * @param {{ label?: string, icon?: string, title?: string, content?: HTMLElement|string }|string} optionsOrIcon
     * @param {string} [label]
     * @param {string} [title]
     */
    ctx.addPanel = (name, optionsOrIcon, label, title) => {
        if (!ctx.sidePanel) return;

        // Normalise: support positional args (name, icon, label, title)
        // as well as options object  (name, { icon, label, title, content })
        let opts;
        if (typeof optionsOrIcon === 'string') {
            opts = { icon: optionsOrIcon, label: label || name, title: title || label || name };
        } else if (optionsOrIcon && typeof optionsOrIcon === 'object') {
            opts = optionsOrIcon;
        } else {
            opts = {};
        }

        // Add button to panel bar
        if (ctx.panelBar) {
            const btn = razyui.spell('div.grid-table-bar-btn', true);
            btn.attr('name', name);
            btn.html(opts.icon || opts.label || name);
            btn.attr('title', opts.title || opts.label || name);
            ctx.panelBar.append(btn);
        }

        // Resolve body element
        let bodyEl;
        if (opts.content instanceof HTMLElement) {
            bodyEl = razyui(opts.content);
        } else if (typeof opts.content === 'string') {
            bodyEl = razyui.el('div', { innerHTML: opts.content });
        } else {
            bodyEl = razyui.el('div');
        }

        // Append to panel-body DOM so activatePanel can show it
        const panelBody = ctx.sidePanel.find('.grid-table-panel-body');
        if (panelBody[0]) {
            bodyEl.css('display', 'none');
            panelBody.append(bodyEl);
        }

        // Register section
        ctx.panelSections[name] = {
            title:  opts.title || opts.label || name,
            label:  opts.label || name,
            bodyEl: bodyEl[0],
        };

        return bodyEl[0];
    };
}

export default installPanel;
